#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
CI MAXN=2005;
/*
1.
f[u][j]表示以u为根的子树，总共花费j的容量，能获得的最大价值
2.
只选u自己，容量>=v[u]时价值为w[u]
FOR(i,v[u],m)f[u][i]=w[u];
3.
给子树to分配k的容量，剩余容量给u本身和之前的子树
*/
int n,m,f[MAXN][MAXN],w[MAXN],v[MAXN],rt;
vector<int> g[MAXN];
void dfs(int u)
{
	FOR(i,v[u],m)f[u][i]=w[u];
	FOR(i,0,(int)g[u].size()-1)
	{
		int to=g[u][i];
		dfs(to);
		ROF(j,m,v[u])
			FOR(k,0,j-v[u])
				f[u][j]=max(f[u][j],f[u][j-k]+f[to][k]);
	}
}
signed main(void)
{
	IOS
    cin>>n>>m;
	FOR(i,1,n)
	{
        int p;
		cin>>p>>w[i];
		v[i]=1;
		if(p==-1)rt=i;
		else g[p].pb(i);
	}
	dfs(rt);
	cout<<f[rt][m];
	return false;
}
